package api

import (
	"errors"
	"testing"

	"github.com/stretchr/testify/assert"
	apierrors "k8s.io/apimachinery/pkg/api/errors"
	"k8s.io/apimachinery/pkg/runtime/schema"
)

func TestErrAgentRuntimeNotFound(t *testing.T) {
	assert.Equal(t, "agent runtime not found", ErrAgentRuntimeNotFound.Error())
}

func TestErrCodeInterpreterNotFound(t *testing.T) {
	assert.Equal(t, "code interpreter not found", ErrCodeInterpreterNotFound.Error())
}

func TestErrTemplateMissing(t *testing.T) {
	assert.Equal(t, "resource has no pod template", ErrTemplateMissing.Error())
}

func TestErrPublicKeyMissing(t *testing.T) {
	assert.Equal(t, "public key not yet loaded from Router Secret", ErrPublicKeyMissing.Error())
}

func TestErrNotFound(t *testing.T) {
	assert.Equal(t, "store: not found", ErrNotFound.Error())
}

func TestNewSessionNotFoundError(t *testing.T) {
	sessionID := "test-session-123"
	err := NewSessionNotFoundError(sessionID)

	statusErr, ok := err.(apierrors.APIStatus)
	assert.True(t, ok, "error should implement APIStatus")
	assert.Equal(t, int32(404), statusErr.Status().Code)
	assert.Equal(t, sessionID, statusErr.Status().Details.Name)
	assert.Equal(t, resourceGroup, statusErr.Status().Details.Group)
	assert.Equal(t, sessionResourceName, statusErr.Status().Details.Kind)
}

func TestNewSandboxTemplateNotFoundError_AgentRuntime(t *testing.T) {
	namespace := "default"
	name := "my-runtime"
	kind := "AgentRuntime"

	err := NewSandboxTemplateNotFoundError(namespace, name, kind)

	statusErr, ok := err.(apierrors.APIStatus)
	assert.True(t, ok, "error should implement APIStatus")
	assert.Equal(t, int32(404), statusErr.Status().Code)
	assert.Equal(t, name, statusErr.Status().Details.Name)
	assert.Equal(t, resourceGroup, statusErr.Status().Details.Group)
	assert.Equal(t, agentRuntimeResourceName, statusErr.Status().Details.Kind)
}

func TestNewSandboxTemplateNotFoundError_CodeInterpreter(t *testing.T) {
	namespace := "default"
	name := "my-interpreter"
	kind := "CodeInterpreter"

	err := NewSandboxTemplateNotFoundError(namespace, name, kind)

	statusErr, ok := err.(apierrors.APIStatus)
	assert.True(t, ok, "error should implement APIStatus")
	assert.Equal(t, int32(404), statusErr.Status().Code)
	assert.Equal(t, name, statusErr.Status().Details.Name)
	assert.Equal(t, resourceGroup, statusErr.Status().Details.Group)
	assert.Equal(t, codeInterpreterResourceName, statusErr.Status().Details.Kind)
}

func TestNewSandboxTemplateNotFoundError_DefaultKind(t *testing.T) {
	namespace := "default"
	name := "my-resource"
	kind := "UnknownKind"

	err := NewSandboxTemplateNotFoundError(namespace, name, kind)

	statusErr, ok := err.(apierrors.APIStatus)
	assert.True(t, ok, "error should implement APIStatus")
	assert.Equal(t, agentRuntimeResourceName, statusErr.Status().Details.Kind)
}

func TestNewUpstreamUnavailableError(t *testing.T) {
	originalErr := errors.New("connection refused")
	err := NewUpstreamUnavailableError(originalErr)

	assert.Contains(t, err.Error(), "upstream unavailable")
	assert.Contains(t, err.Error(), "connection refused")
}

func TestNewInternalError(t *testing.T) {
	originalErr := errors.New("database connection failed")
	err := NewInternalError(originalErr)

	assert.Contains(t, err.Error(), "internal server error")
	assert.Contains(t, err.Error(), "database connection failed")
}

func TestResourceGroupConstant(t *testing.T) {
	assert.Equal(t, "agentcube.volcano.sh", resourceGroup)
}

func TestResourceNames(t *testing.T) {
	assert.Equal(t, "sessions", sessionResourceName)
	assert.Equal(t, "agentruntimes", agentRuntimeResourceName)
	assert.Equal(t, "codeinterpreters", codeInterpreterResourceName)
}

func TestErrorImplementsAPIStatus(t *testing.T) {
	testCases := []struct {
		name string
		err  error
	}{
		{
			name: "session not found",
			err:  NewSessionNotFoundError("test-session"),
		},
		{
			name: "agent runtime not found",
			err:  NewSandboxTemplateNotFoundError("default", "test-runtime", "AgentRuntime"),
		},
		{
			name: "code interpreter not found",
			err:  NewSandboxTemplateNotFoundError("default", "test-interpreter", "CodeInterpreter"),
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			statusErr, ok := tc.err.(apierrors.APIStatus)
			assert.True(t, ok, "error should implement APIStatus interface")
			assert.NotNil(t, statusErr.Status())
		})
	}
}

func TestGroupResourceValues(t *testing.T) {
	err := NewSessionNotFoundError("test-id")
	statusErr := err.(apierrors.APIStatus)
	gr := statusErr.Status().Details.GroupResource

	expectedGR := schema.GroupResource{
		Group:    resourceGroup,
		Resource: sessionResourceName,
	}
	assert.Equal(t, expectedGR, gr)
}

