package types

import (
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
)

func TestKindConstants(t *testing.T) {
	assert.Equal(t, "AgentRuntime", AgentRuntimeKind)
	assert.Equal(t, "CodeInterpreter", CodeInterpreterKind)
	assert.Equal(t, "Sandbox", SandboxKind)
	assert.Equal(t, "SandboxClaim", SandboxClaimsKind)
}

func TestSandboxInfoStruct(t *testing.T) {
	now := time.Now()
	info := SandboxInfo{
		Kind:             "AgentRuntime",
		SandboxID:        "sb-123",
		SandboxNamespace: "default",
		Name:             "my-sandbox",
		EntryPoints: []SandboxEntryPoint{
			{
				Path:     "/",
				Protocol: "HTTP",
				Endpoint: "10.0.0.1:8080",
			},
		},
		SessionID: "session-456",
		CreatedAt: now,
		ExpiresAt: now.Add(time.Hour),
		Status:    "running",
	}

	assert.Equal(t, "AgentRuntime", info.Kind)
	assert.Equal(t, "sb-123", info.SandboxID)
	assert.Equal(t, "default", info.SandboxNamespace)
	assert.Equal(t, "my-sandbox", info.Name)
	assert.Len(t, info.EntryPoints, 1)
	assert.Equal(t, "session-456", info.SessionID)
	assert.Equal(t, now, info.CreatedAt)
	assert.Equal(t, now.Add(time.Hour), info.ExpiresAt)
	assert.Equal(t, "running", info.Status)
}

func TestSandboxEntryPointStruct(t *testing.T) {
	ep := SandboxEntryPoint{
		Path:     "/api",
		Protocol: "HTTPS",
		Endpoint: "10.0.0.2:8443",
	}

	assert.Equal(t, "/api", ep.Path)
	assert.Equal(t, "HTTPS", ep.Protocol)
	assert.Equal(t, "10.0.0.2:8443", ep.Endpoint)
}

func TestCreateSandboxRequestStruct(t *testing.T) {
	req := CreateSandboxRequest{
		Kind:      "CodeInterpreter",
		Name:      "my-interpreter",
		Namespace: "test-ns",
	}

	assert.Equal(t, "CodeInterpreter", req.Kind)
	assert.Equal(t, "my-interpreter", req.Name)
	assert.Equal(t, "test-ns", req.Namespace)
}

func TestCreateSandboxRequestValidate_Valid(t *testing.T) {
	req := CreateSandboxRequest{
		Kind:      "AgentRuntime",
		Name:      "my-runtime",
		Namespace: "default",
	}

	err := req.Validate()
	assert.NoError(t, err)
}

func TestCreateSandboxRequestValidate_EmptyNamespace(t *testing.T) {
	req := CreateSandboxRequest{
		Kind:      "AgentRuntime",
		Name:      "my-runtime",
		Namespace: "",
	}

	err := req.Validate()
	assert.Error(t, err)
	assert.Contains(t, err.Error(), "namespace is required")

	validationErr, ok := err.(*ValidationError)
	assert.True(t, ok)
	assert.Equal(t, "namespace", validationErr.Field)
}

func TestCreateSandboxRequestValidate_EmptyName(t *testing.T) {
	req := CreateSandboxRequest{
		Kind:      "CodeInterpreter",
		Name:      "",
		Namespace: "default",
	}

	err := req.Validate()
	assert.Error(t, err)
	assert.Contains(t, err.Error(), "name is required")

	validationErr, ok := err.(*ValidationError)
	assert.True(t, ok)
	assert.Equal(t, "name", validationErr.Field)
}

func TestValidationError(t *testing.T) {
	err := &ValidationError{
		Field:   "testField",
		Message: "test message",
	}

	assert.Equal(t, "testField", err.Field)
	assert.Equal(t, "test message", err.Message)
	assert.Equal(t, "test message", err.Error())
}

func TestCreateSandboxResponseStruct(t *testing.T) {
	resp := CreateSandboxResponse{
		SessionID:   "sess-789",
		SandboxID:   "sb-abc",
		SandboxName: "my-sandbox-name",
		EntryPoints: []SandboxEntryPoint{
			{
				Path:     "/health",
				Protocol: "HTTP",
				Endpoint: "192.168.1.1:8080",
			},
			{
				Path:     "/api",
				Protocol: "HTTPS",
				Endpoint: "192.168.1.1:8443",
			},
		},
	}

	assert.Equal(t, "sess-789", resp.SessionID)
	assert.Equal(t, "sb-abc", resp.SandboxID)
	assert.Equal(t, "my-sandbox-name", resp.SandboxName)
	assert.Len(t, resp.EntryPoints, 2)
	assert.Equal(t, "/health", resp.EntryPoints[0].Path)
	assert.Equal(t, "/api", resp.EntryPoints[1].Path)
}

func TestSandboxInfoWithMultipleEntryPoints(t *testing.T) {
	info := SandboxInfo{
		Kind:      "CodeInterpreter",
		Name:      "test-sandbox",
		SessionID: "session-xyz",
		EntryPoints: []SandboxEntryPoint{
			{Path: "/", Protocol: "HTTP", Endpoint: "10.0.0.1:80"},
			{Path: "/api", Protocol: "HTTPS", Endpoint: "10.0.0.1:443"},
			{Path: "/ws", Protocol: "HTTP", Endpoint: "10.0.0.1:8080"},
		},
	}

	assert.Len(t, info.EntryPoints, 3)
	assert.Equal(t, "/", info.EntryPoints[0].Path)
	assert.Equal(t, "/api", info.EntryPoints[1].Path)
	assert.Equal(t, "/ws", info.EntryPoints[2].Path)
}

func TestSandboxInfoJSONTags(t *testing.T) {
