package store

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"

	"github.com/valkey-io/valkey-go"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

// ValkeyStore implements Store using Valkey
type ValkeyStore struct {
	client valkey.Client
}

func newValkeyStore() *ValkeyStore {
	addrs := os.Getenv("VALKEY_ADDR")
	if addrs == "" {
		klog.Fatal("VALKEY_ADDR environment variable is not set")
	}

	addresses := strings.Split(addrs, ",")
	if len(addresses) == 0 {
		klog.Fatal("VALKEY_ADDR must contain at least one address")
	}

	password := os.Getenv("VALKEY_PASSWORD")
	passwordRequired := true
	if v := os.Getenv("VALKEY_PASSWORD_REQUIRED"); v != "" {
		passwordRequired, _ = strconv.ParseBool(strings.ToLower(v))
	}

	if passwordRequired && password == "" {
		klog.Fatal("VALKEY_PASSWORD is required but not set")
	}

	disableCache := false
	if v := os.Getenv("VALKEY_DISABLE_CACHE"); v != "" {
		disableCache, _ = strconv.ParseBool(strings.ToLower(v))
	}

	forceSingle := false
	if v := os.Getenv("VALKEY_FORCE_SINGLE"); v != "" {
		forceSingle, _ = strconv.ParseBool(strings.ToLower(v))
	}

	client, err := valkey.NewClient(valkey.ClientOption{
		InitAddress:       addresses,
		Password:          password,
		DisableCache:      disableCache,
		ForceSingleClient: forceSingle,
	})
	if err != nil {
		klog.Fatalf("failed to create valkey client: %v", err)
	}

	return &ValkeyStore{client: client}
}

func (s *ValkeyStore) Ping(ctx context.Context) error {
	result := s.client.Do(ctx, s.client.B().Ping().Build())
	if result.Error() != nil {
		return result.Error()
	}
	return nil
}

func (s *ValkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := sessionKeyPrefix + sessionID
	result := s.client.Do(ctx, s.client.B().Get().Key(key).Build())
	if result.Error() != nil {
		if valkey.IsValkeyNil(result.Error()) {
			return nil, ErrNotFound
		}
		return nil, result.Error()
	}

	data, err := result.ToString()
	if err != nil {
		return nil, err
	}

	var info types.SandboxInfo
	if err := json.Unmarshal([]byte(data), &info); err != nil {
		return nil, err
	}
	return &info, nil
}

func (s *ValkeyStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox is nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return errors.New("sandbox ExpiresAt is zero")
	}

	key := sessionKeyPrefix + sandbox.SessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	commands := []valkey.Completed{
		s.client.B().Setnx().Key(key).Value(string(data)).Build(),
		s.client.B().Zadd().Key(sessionExpiryKey).ScoreMember().ScoreMember(
			float64(sandbox.ExpiresAt.Unix()), sandbox.SessionID,
		).Build(),
		s.client.B().Zadd().Key(sessionLastActivityKey).ScoreMember().ScoreMember(
			float64(time.Now().Unix()), sandbox.SessionID,
		).Build(),
	}

	for _, cmd := range commands {
		result := s.client.Do(ctx, cmd)
		if result.Error() != nil {
			return result.Error()
		}
	}
	return nil
}

func (s *ValkeyStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox is nil")
	}

	key := sessionKeyPrefix + sandbox.SessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	// Use XX to ensure key exists
	result := s.client.Do(ctx, s.client.B().Set().Key(key).Value(string(data)).Xx().Build())
	if result.Error() != nil {
		return result.Error()
	}

	// Check if key was set (XX returns nil if key doesn't exist)
	if valkey.IsValkeyNil(result.Error()) {
		return errors.New("key not exists")
	}

	return nil
}

func (s *ValkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKeyPrefix + sessionID

	commands := []valkey.Completed{
		s.client.B().Del().Key(key).Build(),
		s.client.B().Zrem().Key(sessionExpiryKey).Member(sessionID).Build(),
		s.client.B().Zrem().Key(sessionLastActivityKey).Member(sessionID).Build(),
	}

	for _, cmd := range commands {
		result := s.client.Do(ctx, cmd)
		if result.Error() != nil && !valkey.IsValkeyNil(result.Error()) {
			return result.Error()
		}
	}
	return nil
}

func (s *ValkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return s.listSandboxesByZSet(ctx, sessionExpiryKey, 0, before.Unix(), limit)
}

func (s *ValkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return s.listSandboxesByZSet(ctx, sessionLastActivityKey, 0, before.Unix(), limit)
}

func (s *ValkeyStore) listSandboxesByZSet(ctx context.Context, zsetKey string, min, max int64, limit int64) ([]*types.SandboxInfo, error) {
	result := s.client.Do(ctx, s.client.B().Zrangebyscore().Key(zsetKey).Min(fmt.Sprintf("%d", min)).Max(fmt.Sprintf("%d", max)).Limit().OffsetCount(0, limit).Build())
	if result.Error() != nil {
		return nil, result.Error()
	}

	ids, err := result.AsStrSlice()
	if err != nil {
		return nil, err
	}

	if len(ids) == 0 {
		return []*types.SandboxInfo{}, nil
	}

	// Get all session data
	keys := make([]string, len(ids))
	for i, id := range ids {
		keys[i] = sessionKeyPrefix + id
	}

	results := s.client.Do(ctx, s.client.B().Mget().Key(keys...).Build())
	if results.Error() != nil {
		return nil, results.Error()
	}

	sandboxes := make([]*types.SandboxInfo, 0, len(ids))
	dataSlice, err := results.ToArray()
	if err != nil {
		return nil, err
	}

	for i, dataResult := range dataSlice {
		data, err := dataResult.ToString()
		if err != nil || data == "" {
			// Skip entries where data is missing or empty
			continue
		}
		var info types.SandboxInfo
		if err := json.Unmarshal([]byte(data), &info); err != nil {
			klog.Warningf("failed to unmarshal sandbox %s: %v", ids[i], err)
			continue
		}
		sandboxes = append(sandboxes, &info)
	}

	return sandboxes, nil
}

func (s *ValkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("sessionID is empty")
	}

	key := sessionKeyPrefix + sessionID
	exists := s.client.Do(ctx, s.client.B().Exists().Key(key).Build())
	if exists.Error() != nil {
		return exists.Error()
	}

	count, err := exists.ToInt64()
	if err != nil {
		return err
	}
	if count == 0 {
		return ErrNotFound
	}

	if at.IsZero() {
		at = time.Now()
	}

	result := s.client.Do(ctx, s.client.B().Zadd().Key(sessionLastActivityKey).ScoreMember().ScoreMember(
		float64(at.Unix()), sessionID,
	).Build())
	return result.Error()
}

func (s *ValkeyStore) Close() error {
	s.client.Close()
	return nil
}

